import {cn} from '@/lib/utils';

type NavRailItem = {
  id: string;
  icon: React.ElementType;
  label: string;
};

type NavRailProps = {
  items: NavRailItem[];
  activeId?: string;
  onSelect: (id: string) => void;
  /** Optional bottom-anchored action (e.g. Settings button). */
  footer?: React.ReactNode;
  className?: string;
};

/**
 * Vertical icon rail for primary app navigation. 48px wide, icon-only with
 * tooltip titles. Active item gets primary-wash fill; inactive items are
 * muted with hover state.
 *
 * Decoupled from any store — accepts items + activeId as props so it can be
 * embedded in Storybook and used in any shell context.
 *
 * @example
 * <NavRail
 *   items={[{id: 'app', icon: Layers, label: 'Applications'}]}
 *   activeId="app"
 *   onSelect={setActiveTab}
 *   footer={<NavRailSettingsButton onClick={openSettings} />}
 * />
 */
function NavRail({items, activeId, onSelect, footer, className}: NavRailProps) {
  return (
    <nav
      className={cn(
        'flex w-12 shrink-0 flex-col items-center gap-1 border-r border-border bg-card py-2',
        className
      )}
      style={{boxShadow: 'inset 0 1px 0 var(--highlight)'}}
    >
      {/* Docker whale mark at top */}
      <div className="mb-2 flex size-8 items-center justify-center">
        <NavRailWhaleIcon className="size-5 text-muted-foreground" />
      </div>

      {/* Primary nav items */}
      {items.map(item => (
        <button
          key={item.id}
          type="button"
          onClick={() => onSelect(item.id)}
          title={item.label}
          aria-label={item.label}
          aria-current={item.id === activeId ? 'page' : undefined}
          className={cn(
            'flex size-8 items-center justify-center rounded-[var(--dds-radius-default)] transition-colors',
            item.id === activeId
              ? 'bg-primary-wash text-primary'
              : 'text-muted-foreground hover:bg-hover-overlay hover:text-foreground'
          )}
        >
          <item.icon className="size-4" aria-hidden />
        </button>
      ))}

      <div className="flex-1" />

      {footer}
    </nav>
  );
}

